def build_summary(tasks):
    lines = ["SMART TASK TRACKER"]
    open_count = 0
    done_count = 0

    for task in tasks:
        lines.append(task.summary())
        if task.status == "done":
            done_count += 1
        else:
            open_count += 1

    lines.append(f"OPEN: {open_count} | DONE: {done_count}")
    return "\n".join(lines)

